from leann import LeannBuilder
from leann.api import LeannSearcher, PassageManager
from pathlib import Path
import json

def add_documents_to_existing_index(
    index_path: str,
    new_documents: List[Dict[str, Any]]
) -> Dict[str, Any]:
    if not new_documents:
        raise ValueError("new_documents cannot be empty")

    index_path_obj = Path(index_path)
    if not index_path_obj.exists():
        raise FileNotFoundError(f"Index file not found at {index_path}")

    index_dir = index_path_obj.parent
    index_name = index_path_obj.name

    # Try to get original passage count from metadata
    meta_path = index_dir / f"{index_name}.meta.json"
    original_passage_count = 0
    if meta_path.exists():
        try:
            with open(meta_path, 'r') as f:
                meta = json.load(f)
                original_passage_count = meta.get('total_passages', 0)
        except Exception:
            pass

    # Fallback to counting passages in the source file
    if original_passage_count == 0:
        passage_source = index_dir / f"{index_name}.passages.jsonl"
        if passage_source.exists():
            try:
                original_passage_count = sum(1 for _ in open(passage_source, 'r'))
            except Exception:
                pass

    searcher = LeannSearcher(index_path=index_path)
    passage_manager: PassageManager = searcher.passage_manager

    existing_passages = []
    for source in passage_manager._passage_sources:  # type: ignore
        source_path = Path(source)
        if not source_path.exists():
            continue
        with open(source_path, 'r') as f:
            for line in f:
                try:
                    existing_passages.append(json.loads(line.strip()))
                except Exception:
                    continue

    combined_passages = existing_passages + new_documents

    builder = LeannBuilder()
    builder.add_text(passages=combined_passages)
    builder.build_index(str(index_path))

    new_passage_count = len(combined_passages)
    documents_added = len(new_documents)

    return {
        "original_passage_count": original_passage_count,
        "new_passage_count": new_passage_count,
        "documents_added": documents_added
    }

def rebuild_index_if_needed(index_path: str, min_passage_count: int = 0) -> Dict[str, Any]:
    index_path_obj = Path(index_path)
    index_dir = index_path_obj.parent
    index_name = index_path_obj.name

    meta_path = index_dir / f"{index_name}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError(f"Index metadata file not found at {meta_path}")

    with open(meta_path, 'r') as f:
        meta = json.load(f)
    passage_count = meta.get('total_passages', 0)

    if passage_count >= min_passage_count:
        return {
            "was_rebuilt": False,
            "passage_count": passage_count,
            "action_taken": "no_action"
        }

    passage_source = index_dir / f"{index_name}.passages.jsonl"
    if not passage_source.exists():
        raise FileNotFoundError(f"Passage source file not found at {passage_source}")

    existing_passages = []
    with open(passage_source, 'r') as f:
        for line in f:
            try:
                existing_passages.append(json.loads(line.strip()))
            except Exception:
                continue

    builder = LeannBuilder()
    builder.add_text(passages=existing_passages)
    builder.build_index(str(index_path))

    return {
        "was_rebuilt": True,
        "passage_count": len(existing_passages),
        "action_taken": "rebuilt"
    }

